settings.custom_css:
/* Только десктоп */
@media (min-width: 1025px) {

  .home-card-leinst {
    overflow: hidden;
  }

  /* Картинка */
  .img-for-card-leinst img {
    height: 400px;
    transition: 0.4s ease;
  }

  /* Кнопка скрыта */
  .btn-for-card {
    opacity: 0;
    transform: translateY(20px);
    transition: 0.4s ease;
    pointer-events: none;
  }

  /* Hover */
  .home-card-leinst:hover .img-for-card-leinst img {
    height: 318px;
  }

  .home-card-leinst:hover .btn-for-card {
    opacity: 1;
    transform: translateY(0);
    pointer-events: auto;
  }
}

/* Для планшета и мобилки — всё убрано */
@media (max-width: 1024px) {
  .home-card-leinst {
    max-height: none !important;
    overflow: visible;
    transition: none;
  }

  .img-for-card-leinst img {
    transition: none;
    height: auto;
  }
}

.container-large {
    width: 100%;
    max-width: 50rem;
    margin-left: auto;
    margin-right: auto;
}

.padding-section-large {
    color: #000;
    padding-top: 0px;
    padding-bottom: 0px;
    position: relative;
}

.process_component {

    align-items: start;
    display: grid;
}
@media screen and (max-width: 767px) {
	.process_component {
    	grid-column-gap: 8px;
	}
}

.process_bar {
    justify-content: center;
    height: 85%;
    margin-top: 40px;
    display: flex;
    position: relative;
}

.process_bar-background {
    clip-path: inset(0% 0% round 0px);
    background-color:#F5F5F5;
    border-radius: 1rem;
    width: 8px;
    height: 100%;
    position: absolute;
    top: 0%;
    bottom: 0%;
    left: 1rem;
    right: 1rem;
    overflow: hidden;
}
@media screen and (max-width: 767px) {
	.process_bar-background {
		clip-path: inset(0% 0% round 6px);
		width: 6px;
		left: 13px;
	}
}

.process_bar-background-active {
    background-color:#1B5E20;
	opacity: 1;
    border-radius: 1rem;
    width: 8px;
    height: 100%;
    position: fixed;
    bottom: 49%;
}

@media screen and (max-width: 767px) {
	.process_bar-background-active {
		width: 10px;
		bottom: 49%;/*!*/
	}
}

.process_indicator {
   /* background-color: #5C5C5C;*/
	opacity: 1;
    color: #fff;
    border-radius: 100%;
    justify-content: center;
    align-items: center;
    width: 40px;
    height: 40px;
    display: flex;
    position: -webkit-sticky;
    position: sticky;
	top: 49%;/*!*/
}
@media screen and (max-width: 767px) {
	.process_indicator {
	    width: 32px;
	    height: 32px;
	}
}

.icon_process_indicator {
    justify-content: center;
    align-items: center;
    display: flex;
    overflow: hidden;
}

.process_content-right {
    margin-bottom: 16px;
}
@media screen and (max-width: 767px) {
    .process_content-right {
        flex-direction: column;
        display: flex;
        padding-left: 0px;
    }
}

.process_content-item {
	display: flex;
	flex-direction: column;
	width: 100%;
	opacity: 1;
	filter: none;
	background-color: #FFFFFF;
	border: 1px solid #F1F1F1;
	border-radius: 0;
	margin-bottom: 16px;
	padding: 24px;
	position: relative;
	box-sizing: border-box;
	transition: none;
}

.process_content-item img {
    display: block;
	opacity: 1;
	width: 40px;
	height: 40px;
	margin-right: 16px;
    object-fit: contain;
    object-position: center center;
}

@media (max-width: 767px) {
	.process_content-item img {
		width: 40px;
		height: 40px;
		margin-right: 16px;
	}
}

.content {
	display: flex;
	align-items: center;
	margin-top: 24px;
	margin-bottom: 16px;
}

@media screen and (max-width: 767px) {
    .process_content-item {
        padding: 15px;
		flex-wrap: wrap;
    }    
}


@media screen and (max-width: 767px) {
    .process_content-item.active {
        padding: 15px;
    	margin-left: 8px;
    	margin-right: -8px;
    }    
}

.process_content-item.active img {
	opacity: 1;
	transition: all .3s ease-out 0s;
}

.process_item-heading {
	font-family: "Inter", Sans-serif;
	font-weight: 500 !important;
    font-size: 24px;
    line-height: 120%;
	color: #121212;
	padding: 0px;
	margin: 0px;
}
@media screen and (max-width: 767px) {
    .process_item-heading {
        font-size: 24px;
		line-height: 120%;
    }
}

.text-color-gray {
	font-family: "Inter", Sans-serif;
	font-weight: 500;
    font-size: 16px;
    color: #444457;
    line-height: 150%;
	/*margin: 8px;*/
}
@media screen and (max-width: 767px) {
	.text-color-gray {
		font-size: 15px;
		line-height: 140%;
	}
}
